#### 任务：添加 API 速率限制

**技术方案**：

```typescript
// src/dashboard/middleware/rate-limit.ts
import { FastifyRequest, FastifyReply } from 'fastify';

const rateLimiter = new Map<string, { count: number; resetTime: number }>();

export async function rateLimitMiddleware(
  request: FastifyRequest,
  reply: FastifyReply
) {
  const ip = request.ip;
  const now = Date.now();
  const windowMs = 60 * 1000; // 1 分钟
  const maxRequests = 100; // 每分钟最多 100 次

  const record = rateLimiter.get(ip);

  if (!record || now > record.resetTime) {
    rateLimiter.set(ip, { count: 1, resetTime: now + windowMs });
  } else {
    record.count++;

    if (record.count > maxRequests) {
      return reply.code(429).send({
        success: false,
        error: { message: 'Too many requests', code: 'RATE_LIMIT_EXCEEDED' }
      });
    }
  }

  // 添加速率限制响应头
  reply.header('X-RateLimit-Limit', maxRequests.toString());
  reply.header('X-RateLimit-Remaining', (maxRequests - record.count).toString());
  reply.header('X-RateLimit-Reset', new Date(record.resetTime).toISOString());
}
```

**预估时间**：1-2 小时

