const wsConnections = new Map();

fastify.get('/ws', { websocket: true }, async (connection, req) => {
  const ip = req.ip;
  const connectionCount = wsConnections.get(ip) || 0;

  if (connectionCount > 5) {  // 每个IP最多5个连接
    connection.socket.close(1008, 'Too many connections');
    return;
  }

  wsConnections.set(ip, connectionCount + 1);

  connection.socket.on('close', () => {
    wsConnections.set(ip, wsConnections.get(ip) - 1);
  });
});
