##### 1. 创建敏感信息脱敏工具 (`src/utils/sanitizer.ts`)

```typescript
/**
 * 敏感信息脱敏工具
 * 用于过滤和隐藏日志、历史记录中的敏感数据
 */

export interface SanitizeOptions {
  maskPatterns?: RegExp[];
  maskChar?: string;
  keepChars?: number;
}

// 默认敏感信息模式
const DEFAULT_PATTERNS = [
  // API Keys (Bearer token, API key, etc.)
  /(?:api[_-]?key|apikey|authorization|bearer)[:\s]+['"]?([a-zA-Z0-9_\-]{20,})['"]?/gi,

  // JWT Tokens
  /eyJ[a-zA-Z0-9_\-]+\.[a-zA-Z0-9_\-]+\.[a-zA-Z0-9_\-]+/g,

  // Email addresses
  /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g,

  // IP addresses (optional, based on privacy requirements)
  /\b(?:\d{1,3}\.){3}\d{1,3}\b/g,

  // Passwords in configuration
  /(?:password|passwd|pwd)['"]?\s*[:=]\s*['"]?([^'"\s]+)['"]?/gi,

  // Database connection strings
  /(?:mongodb|postgresql|mysql|redis):\/\/[^@]+@[^\/]+/g,
];

export class DataSanitizer {
  private maskPatterns: RegExp[];
  private maskChar: string;
  private keepChars: number;

  constructor(options: SanitizeOptions = {}) {
    this.maskPatterns = options.maskPatterns || DEFAULT_PATTERNS;
    this.maskChar = options.maskChar || '*';
    this.keepChars = options.keepChars || 4;
  }

  /**
   * 脱敏字符串中的敏感信息
   */
  sanitize(input: string): string {
    let result = input;

    for (const pattern of this.maskPatterns) {
      result = result.replace(pattern, (match, ...groups) => {
        // 如果有捕获组，脱敏捕获的内容
        if (groups[0]) {
          return this.maskValue(groups[0]);
        }
        // 否则脱敏整个匹配
        return this.maskValue(match);
      });
    }

    return result;
  }

  /**
   * 脱敏对象（递归处理所有字符串字段）
   */
  sanitizeObject(obj: any): any {
    if (typeof obj === 'string') {
      return this.sanitize(obj);
    }

    if (Array.isArray(obj)) {
      return obj.map(item => this.sanitizeObject(item));
    }

    if (obj && typeof obj === 'object') {
      const sanitized: any = {};
      for (const [key, value] of Object.entries(obj)) {
        // 跳过已知的安全字段
        if (this.isSecureField(key)) {
          sanitized[key] = value;
        } else {
          sanitized[key] = this.sanitizeObject(value);
        }
      }
      return sanitized;
    }

    return obj;
  }

  /**
   * 掩码值：只保留前 N 个字符
   */
  private maskValue(value: string): string {
    if (value.length <= this.keepChars) {
      return this.maskChar.repeat(value.length);
    }
    return value.substring(0, this.keepChars) + this.maskChar.repeat(value.length - this.keepChars);
  }

  /**
   * 判断是否为安全字段（不需要脱敏）
   */
  private isSecureField(key: string): boolean {
    const secureFields = ['timestamp', 'date', 'status', 'role', 'type'];
    return secureFields.some(field => key.toLowerCase().includes(field));
  }
}

// 导出单例
export const sanitizer = new DataSanitizer();
```

##### 2. 增强安全日志系统 (`src/utils/logger.ts`)

```typescript
/**
 * 安全日志系统
 * 带脱敏功能的结构化日志
 */

import pino from 'pino';
import { sanitizer } from './sanitizer';

export enum LogLevel {
  DEBUG = 'debug',
  INFO = 'info',
  WARN = 'warn',
  ERROR = 'error',
}

export interface SecureLogOptions {
  sanitize?: boolean; // 是否脱敏（默认 true）
  redact?: string[];  // pino redact 字段列表
}

export class SecureLogger {
  private logger: pino.Logger;
  private sanitize: boolean;

  constructor(options: SecureLogOptions = {}) {
    this.sanitize = options.sanitize !== false;

    // 配置 pino
    this.logger = pino({
      level: process.env.LOG_LEVEL || 'info',
      transport: {
        target: 'pino-pretty',
        options: {
          colorize: true,
          translateTime: 'SYS:standard',
          ignore: 'pid,hostname',
        },
      },
      redact: options.redact || [
        'apiKey', 'password', 'token', 'secret',
        'authorization', 'credentials'
      ],
    });
  }

  /**
   * 记录调试日志
   */
  debug(message: string, data?: any): void {
    const sanitizedData = this.sanitize && data 
      ? sanitizer.sanitizeObject(data) 
      : data;

    this.logger.debug({ message, ...sanitizedData });
  }

  /**
   * 记录信息日志
   */
  info(message: string, data?: any): void {
    const sanitizedData = this.sanitize && data 
      ? sanitizer.sanitizeObject(data) 
      : data;

    this.logger.info({ message, ...sanitizedData });
  }

  /**
   * 记录警告日志
   */
  warn(message: string, data?: any): void {
    const sanitizedData = this.sanitize && data 
      ? sanitizer.sanitizeObject(data) 
      : data;

    this.logger.warn({ message, ...sanitizedData });
  }

  /**
   * 记录错误日志
   */
  error(message: string, error?: Error | any): void {
    const sanitizedError = this.sanitize && error 
      ? sanitizer.sanitizeObject(error) 
      : error;

    this.logger.error({ message, error: sanitizedError });
  }

  /**
   * 创建子 Logger（带上下文）
   */
  child(context: string): SecureLogger {
    const childLogger = new SecureLogger({ sanitize: this.sanitize });
    childLogger.logger = this.logger.child({ context });
    return childLogger;
  }
}

// 导出全局 logger 实例
export const logger = new SecureLogger();
```

